mapper:
SELECT domain_keyword_id AS domainKeywordId, domain_keyword AS domainKeyword, domain_keyword_description AS domainKeywordDescription, domain_competency_category AS domainCompetencyCategory, domain_base_score AS domainBaseScore, domain_weight AS domainWeight, domain_is_active AS domainIsActive FROM domain_keyword WHERE 1 = 1
AND domain_keyword LIKE CONCAT('%', #{keyword}, '%')
AND domain_competency_category = #{category}
AND domain_is_active = #{isActive}
ORDER BY domain_keyword_id DESC equipment_baseline
SELECT domain_keyword_id AS domainKeywordId, domain_keyword AS domainKeyword, domain_keyword_description AS domainKeywordDescription, domain_competency_category AS domainCompetencyCategory, domain_base_score AS domainBaseScore, domain_weight AS domainWeight, domain_is_active AS domainIsActive FROM domain_keyword WHERE domain_keyword_id = #{domainKeywordId}
